async function checkAccess(){const e=document.getElementById("admin-pass").value,t=document.getElementById("login-error");try{if(await hashString(e)==="4de9a48824f9ca72125798e7eca051baf13c3e3a403d7fdcf0662f4844fd28ea"){document.getElementById("login-section").style.display="none",document.getElementById("stats-content").style.display="block",loadStats()}else t.style.display="block",t.innerText="Incorrect Password"}catch(n){t.style.display="block",t.innerText="Security error."}}async function hashString(e){const t=(new TextEncoder).encode(e),n=await crypto.subtle.digest("SHA-256",t);return Array.from(new Uint8Array(n)).map(e=>e.toString(16).padStart(2,"0")).join("")}async function loadStats(){const e=document.getElementById("visit-count"),t=document.getElementById("raw-json");if(t){e.innerText="Loading...",t.value="Initiating request...";const n="https://api.counterapi.dev/v1/josemanuel31675-cv/visits";try{const s=`https://corsproxy.io/?${encodeURIComponent(n+"?t="+Date.now())}`,a=await fetch(s);if(a.ok){const n=await a.json();t.value=JSON.stringify(n,null,4),e.innerText=n.count;return}}catch(s){}try{const s=`https://api.allorigins.win/get?url=${encodeURIComponent(n)}&t=${Date.now()}`,a=await fetch(s),r=await a.json();if(r&&r.contents){t.value=r.contents;const n=JSON.parse(r.contents);e.innerText=n.count||"0";return}}catch(s){}t.value="CORS block detected. The browser prevented reading the JSON directly.\n\nYou can manually verify the data at:\n"+n;const s=`https://api.counterapi.dev/v1/josemanuel31675-cv/visits/badge.svg?t=${Date.now()}`;e.innerHTML=`<img src="${s}" alt="Visits Badge" style="transform: scale(1.5);">`}}
